-- PG
CREATE TABLE rooms (id TEXT PRIMARY KEY, home_server TEXT, max_depth BIGINT DEFAULT 0);
CREATE TABLE room_events (
  event_id TEXT PRIMARY KEY,
  room_id TEXT NOT NULL REFERENCES rooms(id),
  depth BIGINT NOT NULL,
  origin_server TEXT NOT NULL,
  sender TEXT NOT NULL,
  type TEXT NOT NULL,
  content JSONB NOT NULL,
  prev_events TEXT[] NOT NULL,
  origin_ts TIMESTAMPTZ NOT NULL,
  received_at TIMESTAMPTZ DEFAULT now()
);
CREATE INDEX ON room_events (room_id, depth);
CREATE INDEX ON room_events (room_id, received_at);

CREATE TABLE federation_queue (id BIGSERIAL PK, event_id TEXT, dest_server TEXT, attempts INT DEFAULT 0, next_try_at TIMESTAMPTZ DEFAULT now(), delivered BOOLEAN DEFAULT false, UNIQUE (event_id, dest_server));
CREATE INDEX ON federation_queue (dest_server, delivered, next_try_at);

// Mongo: rooms metadata, members per server

