// src/services/federation.ts
import { pool } from '../infra/pg';
import { io } from '../server';
import { Queue, Worker } from 'bullmq';
import { redis } from '../infra/redis';
import { v4 as uuid } from 'uuid';
import fetch from 'node-fetch';

const fedQ = new Queue('fed:send', { connection: redis });

export async function sendLocalEvent(roomId:string, sender:string, type:string, content:any) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const r = await client.query('SELECT max_depth FROM rooms WHERE id=$1 FOR UPDATE', [roomId]);
    if (!r.rows[0]) { await client.query('ROLLBACK'); throw new Error('no_room'); }
    const depth = Number(r.rows[0].max_depth) + 1;
    const eventId = `${process.env.HOME_SERVER}:${uuid()}`;
    const prevEvents = (await client.query('SELECT event_id FROM room_events WHERE room_id=$1 AND depth=$2', [roomId, depth - 1])).rows.map((r:any) => r.event_id);
    await client.query('INSERT INTO room_events(event_id, room_id, depth, origin_server, sender, type, content, prev_events, origin_ts) VALUES ($1,$2,$3,$4,$5,$6,$7,$8,now())', [eventId, roomId, depth, process.env.HOME_SERVER, sender, type, content, prevEvents]);
    await client.query('UPDATE rooms SET max_depth=$1 WHERE id=$2', [depth, roomId]);
    const { rows: members } = await client.query('SELECT DISTINCT home_server FROM federation_members WHERE room_id=$1 AND home_server != $2', [roomId, process.env.HOME_SERVER]);
    for (const m of members) await client.query('INSERT INTO federation_queue(event_id, dest_server) VALUES ($1,$2) ON CONFLICT DO NOTHING', [eventId, m.home_server]);
    await client.query('COMMIT');
    for (const m of members) await fedQ.add('send', { eventId, destServer: m.home_server }, { jobId: `${eventId}:${m.home_server}` });
    io.of('/federated').to(`room:${roomId}`).emit('event', { eventId, roomId, depth, sender, type, content, originServer: process.env.HOME_SERVER, ts: Date.now() });
    return { eventId, depth };
  } catch (e) { await client.query('ROLLBACK'); throw e; } finally { client.release(); }
}

export async function receiveRemoteEvent(payload:any) {
  const { eventId, roomId, depth, originServer, sender, type, content, prevEvents, originTs } = payload;
  // dedup
  const ins = await pool.query('INSERT INTO room_events(event_id, room_id, depth, origin_server, sender, type, content, prev_events, origin_ts) VALUES ($1,$2,$3,$4,$5,$6,$7,$8,$9) ON CONFLICT DO NOTHING RETURNING event_id', [eventId, roomId, depth, originServer, sender, type, content, prevEvents, originTs]);
  if (ins.rowCount === 0) return { duplicate: true };
  // missing prev_events check
  if (prevEvents.length) {
    const present = await pool.query('SELECT event_id FROM room_events WHERE event_id = ANY($1::text[])', [prevEvents]);
    const missing = prevEvents.filter((id:string) => !present.rows.find((r:any) => r.event_id === id));
    if (missing.length) requestBackfill(originServer, roomId, missing).catch(()=>{});
  }
  await pool.query('UPDATE rooms SET max_depth=GREATEST(max_depth, $1) WHERE id=$2', [depth, roomId]);
  io.of('/federated').to(`room:${roomId}`).emit('event', payload);
  return { ok: true };
}

async function requestBackfill(server:string, roomId:string, eventIds:string[]) {
  const r = await fetch(`https://${server}/federation/backfill`, { method:'POST', body: JSON.stringify({ roomId, eventIds }), headers:{'content-type':'application/json'} });
  if (!r.ok) return;
  const { events } = await r.json() as any;
  for (const e of events) await receiveRemoteEvent(e);
}

export function startFederationWorker() {
  new Worker('fed:send', async (job:any) => {
    const { eventId, destServer } = job.data;
    const { rows } = await pool.query('SELECT event_id, room_id, depth, origin_server, sender, type, content, prev_events, origin_ts FROM room_events WHERE event_id=$1', [eventId]);
    if (!rows[0]) return;
    try {
      const r = await fetch(`https://${destServer}/federation/send`, { method:'POST', body: JSON.stringify(rows[0]), headers:{'content-type':'application/json'}, timeout: 10000 } as any);
      if (!r.ok) throw new Error('http_' + r.status);
      await pool.query('UPDATE federation_queue SET delivered=true WHERE event_id=$1 AND dest_server=$2', [eventId, destServer]);
    } catch (e) { await pool.query('UPDATE federation_queue SET attempts=attempts+1, next_try_at=now()+interval \'30 seconds\' * attempts WHERE event_id=$1 AND dest_server=$2', [eventId, destServer]); throw e; }
  }, { connection: redis });
}

// src/socket/federated.namespace.ts
import { Namespace } from 'socket.io';
import { pool } from '../infra/pg';
import { sendLocalEvent } from '../services/federation';
export function registerFederatedNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    socket.on('room:join', async ({ roomId, sinceDepth }, ack) => {
      if (!await isMember(socket.data.user.id, roomId)) return ack({ error: 'forbidden' });
      await socket.join(`room:${roomId}`);
      const events = await pool.query('SELECT event_id, room_id, depth, origin_server, sender, type, content, origin_ts FROM room_events WHERE room_id=$1 AND depth > $2 ORDER BY depth ASC LIMIT 500', [roomId, sinceDepth ?? 0]);
      const max = await pool.query('SELECT max_depth FROM rooms WHERE id=$1', [roomId]);
      ack({ events: events.rows, maxDepth: Number(max.rows[0]?.max_depth ?? 0) });
    });
    socket.on('msg:send', async ({ roomId, type, content }, ack) => {
      try { const r = await sendLocalEvent(roomId, String(socket.data.user.id), type, content); ack({ eventId: r.eventId }); }
      catch (e:any) { ack({ error: 'send_failed' }); }
    });
  });
}

