// src/hooks/useFederatedRoom.ts
import { useEffect, useRef, useState, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getFedSock(t:string){ if(sock) return sock; sock = io('/federated',{auth:{token:t},transports:['websocket']}); return sock; }
export function useFederatedRoom(roomId:string, token:string) {
  const [events, setEvents] = useState<any[]>([]);
  const seen = useRef(new Set<string>());
  const lastDepthRef = useRef(0);
  useEffect(() => {
    const s = getFedSock(token);
    const join = () => s.emit('room:join',{roomId, sinceDepth: lastDepthRef.current},(r:any)=>{ if(r.error) return; for (const e of r.events) ingest(e); });
    const ingest = (e:any) => { if (seen.current.has(e.event_id || e.eventId)) return; seen.current.add(e.event_id || e.eventId); lastDepthRef.current = Math.max(lastDepthRef.current, e.depth); setEvents(prev => [...prev, e].sort((a,b)=>a.depth-b.depth)); };
    const onEvent = (e:any) => ingest(e);
    s.on('connect', join); s.on('event', onEvent);
    if (s.connected) join();
    return () => { s.off('connect', join); s.off('event', onEvent); };
  }, [roomId, token]);
  const send = useCallback((type:string, content:any) => new Promise((res,rej)=>getFedSock(token).emit('msg:send',{roomId,type,content},(r:any)=>r.error?rej(r):res(r))), [roomId, token]);
  return { events, send };
}

database_design.schema:
CREATE TABLE experiments (id BIGSERIAL PK, name TEXT, status TEXT, started_at TIMESTAMPTZ, ended_at TIMESTAMPTZ);
CREATE TABLE variants (id BIGSERIAL PK, experiment_id BIGINT REFERENCES experiments(id), name TEXT, weight NUMERIC);
CREATE TABLE assignments (
  user_id BIGINT NOT NULL,
  experiment_id BIGINT NOT NULL,
  variant_id BIGINT NOT NULL,
  assigned_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  PRIMARY KEY (user_id, experiment_id)
);
CREATE INDEX ON assignments (experiment_id, variant_id);
CREATE TABLE conversions (id BIGSERIAL PK, user_id BIGINT, experiment_id BIGINT, variant_id BIGINT, value NUMERIC DEFAULT 1, ts TIMESTAMPTZ DEFAULT now());
CREATE INDEX ON conversions (experiment_id, variant_id, ts);

CREATE MATERIALIZED VIEW variant_stats AS
SELECT a.experiment_id, a.variant_id, count(DISTINCT a.user_id) AS assignments, count(DISTINCT c.user_id) AS converters, COALESCE(sum(c.value), 0) AS total_value
FROM assignments a LEFT JOIN conversions c ON c.user_id=a.user_id AND c.experiment_id=a.experiment_id GROUP BY a.experiment_id, a.variant_id;

