// src/services/abTest.ts
import { pool } from '../infra/pg';
import { io } from '../server';
import { redis } from '../infra/redis';
import { ztest2prop } from '../stats/ztest';

export async function assign(userId:number, experimentId:number) {
  // sticky: dedup via PK
  const variants = await pool.query('SELECT id, weight FROM variants WHERE experiment_id=$1', [experimentId]);
  const total = variants.rows.reduce((s,v) => s + Number(v.weight), 0);
  const hash = ((userId * 2654435761) >>> 0) / 0xffffffff;
  let cum = 0; let chosen = variants.rows[0];
  for (const v of variants.rows) { cum += Number(v.weight) / total; if (hash <= cum) { chosen = v; break; } }
  const r = await pool.query('INSERT INTO assignments(user_id, experiment_id, variant_id) VALUES ($1,$2,$3) ON CONFLICT (user_id, experiment_id) DO UPDATE SET variant_id=assignments.variant_id RETURNING variant_id', [userId, experimentId, chosen.id]);
  return Number(r.rows[0].variant_id);
}

export async function trackConversion(userId:number, experimentId:number, value:number) {
  // attribute to assigned variant
  const a = await pool.query('SELECT variant_id FROM assignments WHERE user_id=$1 AND experiment_id=$2', [userId, experimentId]);
  if (!a.rows[0]) return { error: 'not_assigned' };
  await pool.query('INSERT INTO conversions(user_id, experiment_id, variant_id, value) VALUES ($1,$2,$3,$4)', [userId, experimentId, a.rows[0].variant_id, value]);
  await redis.hincrby(`ab:cache:${experimentId}:${a.rows[0].variant_id}`, 'conv', 1);
  return { ok: true };
}

export function startStatsLoop() {
  setInterval(async () => {
    await pool.query('REFRESH MATERIALIZED VIEW CONCURRENTLY variant_stats');
    const { rows } = await pool.query('SELECT experiment_id, variant_id, assignments, converters FROM variant_stats');
    const byExp = new Map<number, any[]>();
    for (const r of rows) { const list = byExp.get(Number(r.experiment_id)) ?? []; list.push(r); byExp.set(Number(r.experiment_id), list); }
    for (const [expId, vs] of byExp) {
      io.of('/ab').to(`exp:${expId}`).emit('stats:update', { experimentId: String(expId), variants: vs });
      if (vs.length === 2) {
        const [a, b] = vs;
        const z = ztest2prop(Number(a.converters), Number(a.assignments), Number(b.converters), Number(b.assignments));
        io.of('/ab').to(`exp:${expId}`).emit('sig:update', { experimentId: String(expId), z: z.z, p: z.p, winner: z.p < 0.05 ? (Number(a.converters)/Number(a.assignments) > Number(b.converters)/Number(b.assignments) ? a.variant_id : b.variant_id) : null });
      }
    }
  }, 10_000);
}

// src/socket/ab.namespace.ts
import { Namespace } from 'socket.io';
import { pool } from '../infra/pg';
export function registerAbNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    socket.on('exp:subscribe', async ({ experimentId }, ack) => {
      await socket.join(`exp:${experimentId}`);
      const { rows } = await pool.query('SELECT variant_id, assignments, converters FROM variant_stats WHERE experiment_id=$1', [experimentId]);
      ack({ variants: rows });
    });
  });
}

