// src/hooks/useExperiment.ts
import { useEffect, useState } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSock(t:string){ if(sock) return sock; sock = io('/ab',{auth:{token:t},transports:['websocket']}); return sock; }
export function useExperiment(experimentId:string, token:string) {
  const [variants, setVariants] = useState<any[]>([]);
  const [sig, setSig] = useState<any>(null);
  useEffect(() => {
    const s = getSock(token);
    const sub = () => s.emit('exp:subscribe',{experimentId},(r:any)=>{ if(r.variants) setVariants(r.variants); });
    const onStats = (e:any) => { if (e.experimentId === experimentId) setVariants(e.variants); };
    const onSig = (e:any) => { if (e.experimentId === experimentId) setSig(e); };
    s.on('connect', sub); s.on('stats:update', onStats); s.on('sig:update', onSig);
    if (s.connected) sub();
    return () => { s.off('connect', sub); s.off('stats:update', onStats); s.off('sig:update', onSig); };
  }, [experimentId, token]);
  return { variants, sig };
}

