// src/socket/mmo.namespace.ts
import { Namespace } from 'socket.io';
import { pool } from '../infra/pg';
import { redis } from '../infra/redis';
import { filterCurses } from '../infra/filter';

export function registerMmoNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    let currentZone: string | null = null;
    let currentParty: string | null = null;
    socket.on('zone:enter', async ({ zoneId }) => {
      if (currentZone) await socket.leave(`zone:${currentZone}`);
      currentZone = zoneId; await socket.join(`zone:${zoneId}`);
    });
    socket.on('party:set', async ({ partyId }) => {
      if (currentParty) await socket.leave(`party:${currentParty}`);
      currentParty = partyId; if (partyId) await socket.join(`party:${partyId}`);
    });
    socket.on('chat:send', async ({ channel, body }, ack) => {
      const key = `cap:${channel}:${userId}`;
      const n = await redis.incr(key); if (n === 1) await redis.expire(key, 10);
      const limits: Record<string,number> = { zone: 10, party: 30, trade: 5 };
      if (n > (limits[channel] ?? 5)) return ack({ error: 'rate_limited' });
      const clean = filterCurses(body);
      let target: string;
      let channelKey: string;
      if (channel === 'zone') { if (!currentZone) return ack({ error: 'no_zone' }); target = `zone:${currentZone}`; channelKey = currentZone; }
      else if (channel === 'party') { if (!currentParty) return ack({ error: 'no_party' }); target = `party:${currentParty}`; channelKey = currentParty; }
      else if (channel === 'trade') { target = 'global:trade'; channelKey = 'trade'; }
      else return ack({ error: 'bad_channel' });
      await pool.query('INSERT INTO chat_logs(channel, channel_key, sender_id, body) VALUES ($1,$2,$3,$4)', [channel, channelKey, userId, clean]);
      socket.to(target).emit('chat', { channel, channelKey, senderId: String(userId), body: clean, ts: Date.now() });
      ack({ ok: true });
    });
  });
}

