// src/hooks/useMmoChat.ts
import { useEffect, useState, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSock(t:string){ if(sock) return sock; sock = io('/mmo',{auth:{token:t},transports:['websocket']}); return sock; }
export function useMmoChat(token:string) {
  const [messages, setMessages] = useState<any[]>([]);
  const [mutes, setMutes] = useState<Set<string>>(new Set());
  useEffect(() => {
    const s = getSock(token);
    const onChat = (m:any) => { if (mutes.has(m.senderId)) return; setMessages(p => [...p.slice(-200), m]); };
    s.on('chat', onChat);
    return () => { s.off('chat', onChat); };
  }, [token, mutes]);
  const send = useCallback((channel:string, body:string) => new Promise((res,rej)=>getSock(token).emit('chat:send',{channel,body},(r:any)=>r.error?rej(r):res(r))), [token]);
  const enterZone = useCallback((zoneId:string) => getSock(token).emit('zone:enter',{zoneId}), [token]);
  const setParty = useCallback((partyId:string|null) => getSock(token).emit('party:set',{partyId}), [token]);
  const mute = useCallback((senderId:string) => setMutes(p => new Set(p).add(senderId)), []);
  return { messages, send, enterZone, setParty, mute };
}

