// src/services/dutch.ts
import { Dutch } from '../models/Dutch';
import { io } from '../server';

export function startDutchTicker() {
  setInterval(async () => {
    const live = await Dutch.find({ status: 'live' });
    for (const a of live) {
      const newPrice = Math.max(a.floorPriceCents!, a.currentPriceCents! - a.stepCents!);
      if (newPrice === a.floorPriceCents && a.currentPriceCents === a.floorPriceCents) {
        await Dutch.updateOne({ _id: a._id, status: 'live' }, { $set: { status: 'expired' } });
        io.of('/dutch').to(`da:${a._id}`).emit('won', { winnerUserId: null, status: 'expired' });
        continue;
      }
      await Dutch.updateOne({ _id: a._id, status: 'live' }, { $set: { currentPriceCents: newPrice } });
      io.of('/dutch').to(`da:${a._id}`).emit('tick', { auctionId: a._id, currentPriceCents: newPrice, ts: Date.now() });
    }
  }, 1000);
}

export async function bid(auctionId:string, userId:string, amountCents:number) {
  const won = await Dutch.findOneAndUpdate(
    { _id: auctionId, status: 'live', currentPriceCents: { $lte: amountCents } },
    { $set: { status: 'won', winnerUserId: userId, wonAtCents: amountCents, wonAt: new Date() } },
    { new: true, projection: { currentPriceCents: 1, wonAtCents: 1 } },
  );
  if (!won) return { error: 'too_late_or_low' };
  io.of('/dutch').to(`da:${auctionId}`).emit('won', { winnerUserId: userId, wonAtCents: won.wonAtCents });
  return { ok: true, wonAtCents: won.wonAtCents };
}

// src/socket/dutch.namespace.ts
import { Namespace } from 'socket.io';
import { Dutch } from '../models/Dutch';
import { bid } from '../services/dutch';
export function registerDutchNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    socket.on('da:watch', async ({ auctionId }, ack) => {
      await socket.join(`da:${auctionId}`);
      const a = await Dutch.findById(auctionId).lean();
      ack({ auction: a });
    });
    socket.on('bid', async ({ auctionId, amountCents }, ack) => {
      const r = await bid(auctionId, String(socket.data.user.id), amountCents);
      ack(r);
    });
  });
}

