// src/hooks/useDutchAuction.ts
import { useEffect, useState, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSock(t:string){ if(sock) return sock; sock = io('/dutch',{auth:{token:t},transports:['websocket']}); return sock; }
export function useDutchAuction(auctionId:string, token:string) {
  const [auction, setAuction] = useState<any>(null);
  useEffect(() => {
    const s = getSock(token);
    const watch = () => s.emit('da:watch',{auctionId},(r:any)=>setAuction(r.auction));
    const onTick = (e:any) => { if (e.auctionId === auctionId) setAuction((a:any) => a ? { ...a, currentPriceCents: e.currentPriceCents } : a); };
    const onWon = (e:any) => setAuction((a:any) => a ? { ...a, status: 'won', winnerUserId: e.winnerUserId, wonAtCents: e.wonAtCents } : a);
    s.on('connect', watch); s.on('tick', onTick); s.on('won', onWon);
    if (s.connected) watch();
    return () => { s.off('connect', watch); s.off('tick', onTick); s.off('won', onWon); };
  }, [auctionId, token]);
  const placeBid = useCallback((amountCents:number) => new Promise((res,rej)=>getSock(token).emit('bid',{auctionId,amountCents},(r:any)=>r.error?rej(r):res(r))), [auctionId, token]);
  return { auction, placeBid };
}

