// src/services/routing.ts
import { pool } from '../infra/pg';
import { io } from '../server';
import { redis } from '../infra/redis';

export async function newChat(customerId:number, requiredSkills:string[]) {
  const ins = await pool.query('INSERT INTO chats(customer_id, required_skills, status) VALUES ($1,$2,$3) RETURNING id', [customerId, requiredSkills, 'queued']);
  const chatId = Number(ins.rows[0].id);
  const ok = await tryRoute(chatId, requiredSkills);
  if (!ok) await redis.zadd(`hd:queue:${requiredSkills.sort().join(',')}`, Date.now(), String(chatId));
  return { chatId };
}

export async function tryRoute(chatId:number, requiredSkills:string[]) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const r = await client.query(`SELECT id FROM agents WHERE status='available' AND skills @> $1 AND current_load < max_concurrent ORDER BY current_load ASC LIMIT 1 FOR UPDATE SKIP LOCKED`, [requiredSkills]);
    if (r.rowCount === 0) { await client.query('ROLLBACK'); return false; }
    const agentId = Number(r.rows[0].id);
    await client.query('UPDATE agents SET current_load=current_load+1 WHERE id=$1', [agentId]);
    await client.query(`UPDATE chats SET assigned_agent_id=$1, status='active', assigned_at=now() WHERE id=$2`, [agentId, chatId]);
    await client.query('COMMIT');
    io.of('/helpdesk').to(`agent:${agentId}`).emit('chat:incoming', { chatId: String(chatId) });
    io.of('/helpdesk').to(`chat:${chatId}`).emit('chat:assigned', { agentId: String(agentId) });
    return true;
  } catch (e) { await client.query('ROLLBACK'); throw e; } finally { client.release(); }
}

export async function agentOffline(agentId:number) {
  await pool.query("UPDATE agents SET status='offline' WHERE id=$1", [agentId]);
  const { rows } = await pool.query(`SELECT id, required_skills FROM chats WHERE assigned_agent_id=$1 AND status='active'`, [agentId]);
  for (const c of rows) {
    await pool.query(`UPDATE chats SET assigned_agent_id=NULL, status='queued' WHERE id=$1`, [c.id]);
    await pool.query('UPDATE agents SET current_load=GREATEST(0, current_load-1) WHERE id=$1', [agentId]);
    await tryRoute(Number(c.id), c.required_skills);
  }
}

// src/socket/helpdesk.namespace.ts
import { Namespace } from 'socket.io';
import { pool } from '../infra/pg';
import { agentOffline } from '../services/routing';
export function registerHelpdeskNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    if (socket.data.user.role === 'agent') {
      socket.join(`agent:${userId}`);
      pool.query(`UPDATE agents SET status='available' WHERE id=$1`, [userId]);
      socket.on('disconnect', () => { agentOffline(Number(userId)); });
    }
  });
}

