// src/services/suggestions.ts
import mongoose from 'mongoose';
import { Suggestion } from '../models/Suggestion';
import { Block } from '../models/Block';
import { io } from '../server';
import { v4 as uuid } from 'uuid';

export async function addSuggestion(input:any, userId:string) {
  const doc = await Block.findById(input.blockId).lean();
  if (!doc) throw new Error('no_block');
  const s = await Suggestion.create({ _id: uuid(), ...input, authorId: userId, baseVersion: doc.version });
  io.of('/docs').to(`doc:${input.docId}`).emit('suggestion:new', s.toObject());
  return s;
}

export async function acceptSuggestion(suggestionId:string, userId:string) {
  const session = await mongoose.startSession();
  try {
    let result:any;
    await session.withTransaction(async () => {
      const s = await Suggestion.findOneAndUpdate({ _id: suggestionId, status: 'open' }, { $set: { status: 'accepted' } }, { new: true, session });
      if (!s) { result = { error: 'already_handled' }; return; }
      // apply to block content
      const block = await Block.findById(s.blockId, null, { session });
      if (!block) { result = { error: 'no_block' }; return; }
      const cur = String(block.content?.text ?? '');
      let next: string;
      if (s.kind === 'insert') next = cur.slice(0, s.range.start) + s.content + cur.slice(s.range.start);
      else if (s.kind === 'delete') next = cur.slice(0, s.range.start) + cur.slice(s.range.end);
      else next = cur.slice(0, s.range.start) + s.content + cur.slice(s.range.end);
      block.content = { ...block.content, text: next }; block.version = (block.version ?? 0) + 1;
      await block.save({ session });
      result = { ok: true, suggestion: s.toObject(), newVersion: block.version };
    });
    if (result.ok) io.of('/docs').to(`doc:${result.suggestion.docId}`).emit('suggestion:changed', { ...result.suggestion, status: 'accepted' });
    return result;
  } finally { await session.endSession(); }
}

export async function rejectSuggestion(suggestionId:string) {
  const s = await Suggestion.findOneAndUpdate({ _id: suggestionId, status: 'open' }, { $set: { status: 'rejected' } }, { new: true });
  if (!s) return { error: 'already_handled' };
  io.of('/docs').to(`doc:${s.docId}`).emit('suggestion:changed', s.toObject());
  return { ok: true };
}

// src/socket/suggestions.namespace.ts (extends docs ns)
import { Namespace } from 'socket.io';
import { Suggestion } from '../models/Suggestion';
import { addSuggestion, acceptSuggestion, rejectSuggestion } from '../services/suggestions';
export function registerSuggestionsHandlers(nsp: Namespace) {
  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    socket.on('suggest:add', async (input, ack) => { try { const s = await addSuggestion(input, userId); ack({ suggestion: s.toObject() }); } catch (e:any) { ack({ error: e.message }); } });
    socket.on('suggest:accept', async ({ suggestionId }, ack) => { const r = await acceptSuggestion(suggestionId, userId); ack(r); });
    socket.on('suggest:reject', async ({ suggestionId }, ack) => { const r = await rejectSuggestion(suggestionId); ack(r); });
    socket.on('doc:openSuggestions', async ({ docId }, ack) => { const list = await Suggestion.find({ docId, status: 'open' }).lean(); ack({ suggestions: list }); });
  });
}

