import { getDocsSocket } from '../socket/docsSocket';
export function useSuggestions(docId:string, token:string) {
  const [suggestions, setSuggestions] = useState<any[]>([]);
  useEffect(() => {
    const s = getDocsSocket(token);
    s.emit('doc:openSuggestions',{docId},(r:any)=>setSuggestions(r.suggestions ?? []));
    const onNew = (sg:any) => { if (sg.docId === docId) setSuggestions(p => [...p, sg]); };
