// src/services/webhookDelivery.ts
import { pool } from '../infra/pg';
import { io } from '../server';
import { Queue, Worker } from 'bullmq';
import { redis } from '../infra/redis';
import crypto from 'crypto';
import fetch from 'node-fetch';

const whQ = new Queue('webhook:deliver', { connection: redis });

export async function dispatchEvent(customerId:number, eventId:string, payload:any) {
  const { rows } = await pool.query('SELECT id FROM webhooks WHERE customer_id=$1 AND enabled=true', [customerId]);
  for (const w of rows) {
    const ins = await pool.query('INSERT INTO webhook_deliveries(webhook_id, event_id, payload, status) VALUES ($1,$2,$3,$4) RETURNING id', [w.id, eventId, payload, 'pending']);
    await whQ.add('deliver', { deliveryId: String(ins.rows[0].id) });
  }
}

export function startWebhookWorker() {
  new Worker('webhook:deliver', async (job:any) => {
    const { deliveryId } = job.data;
    const { rows } = await pool.query(`SELECT d.id, d.webhook_id, d.event_id, d.payload, d.attempts, w.url, w.secret, w.customer_id FROM webhook_deliveries d JOIN webhooks w ON w.id=d.webhook_id WHERE d.id=$1`, [deliveryId]);
    if (!rows[0]) return;
    const d = rows[0];
    const body = JSON.stringify({ eventId: d.event_id, payload: d.payload });
    const sig = crypto.createHmac('sha256', d.secret).update(body).digest('hex');
    try {
      const r = await fetch(d.url, { method:'POST', body, headers: { 'content-type': 'application/json', 'x-signature': `sha256=${sig}`, 'x-event-id': d.event_id }, timeout: 10000 } as any);
      const text = await r.text();
      if (r.ok) {
        await pool.query(`UPDATE webhook_deliveries SET status='delivered', delivered_at=now(), response_code=$1, response_body=$2, attempts=attempts+1 WHERE id=$3`, [r.status, text.slice(0,1000), d.id]);
        io.of('/webhooks').to(`customer:${d.customer_id}`).emit('delivery:update', { deliveryId: String(d.id), status: 'delivered', responseCode: r.status });
      } else {
        const retryAfter = Number(r.headers.get('retry-after')) || null;
        const delay = retryAfter ? retryAfter * 1000 : Math.min(60_000, Math.pow(2, d.attempts) * 1000);
        await pool.query('UPDATE webhook_deliveries SET attempts=attempts+1, response_code=$1, response_body=$2, status=$3, next_try_at=now()+($4 * interval \'1 millisecond\') WHERE id=$5', [r.status, text.slice(0,1000), d.attempts >= 24 ? 'failed' : 'retrying', delay, d.id]);
        io.of('/webhooks').to(`customer:${d.customer_id}`).emit('delivery:update', { deliveryId: String(d.id), status: d.attempts >= 24 ? 'failed' : 'retrying', responseCode: r.status });
        if (d.attempts < 24) await whQ.add('deliver', { deliveryId: String(d.id) }, { delay });
      }
    } catch (e:any) {
      await pool.query('UPDATE webhook_deliveries SET attempts=attempts+1, status=$1 WHERE id=$2', [d.attempts >= 24 ? 'failed' : 'retrying', d.id]);
      if (d.attempts < 24) await whQ.add('deliver', { deliveryId: String(d.id) }, { delay: Math.min(60_000, Math.pow(2, d.attempts) * 1000) });
      else io.of('/webhooks').to(`customer:${d.customer_id}`).emit('delivery:update', { deliveryId: String(d.id), status: 'failed' });
    }
  }, { connection: redis });
}

