import { Namespace } from 'socket.io';
import { pool } from '../infra/pg';
import { sipClient } from '../infra/sip';
import { io } from '../server';

export function registerVoipNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    const agentId = socket.data.user.id;
    socket.on('call:dial', async ({ callee }, ack) => {
      const ins = await pool.query(`INSERT INTO calls(agent_id, callee_e164, direction, status) VALUES ($1,$2,'outbound','dialing') RETURNING id`, [agentId, callee]);
      const callId = ins.rows[0].id;
      await socket.join(`call:${callId}`);
      try {
        const sip = await sipClient.dial(callee);
        await pool.query('UPDATE calls SET sip_call_id=$1, started_at=now() WHERE id=$2', [sip.callId, callId]);
        sipClient.on(sip.callId, async (ev) => {
          await pool.query('INSERT INTO call_events(call_id, event, payload) VALUES ($1,$2,$3)', [callId, ev.type, ev]);
          io.of('/voip').to(`call:${callId}`).emit('call:state', { callId: String(callId), ...ev });
          if (ev.type === 'ended') { await pool.query("UPDATE calls SET status='ended', ended_at=now(), duration_sec=$1, cost_cents=$2 WHERE id=$3", [ev.durationSec, ev.costCents, callId]); }
        });
        ack({ callId: String(callId) });
      } catch (e:any) { await pool.query("UPDATE calls SET status='failed' WHERE id=$1", [callId]); ack({ error: 'dial_failed' }); }
    });
    socket.on('call:control', async ({ callId, action }, ack) => {
      const r = await pool.query('SELECT sip_call_id FROM calls WHERE id=$1 AND agent_id=$2', [callId, agentId]);
      if (!r.rows[0]) return ack({ error: 'forbidden' });
      try { await sipClient.control(r.rows[0].sip_call_id, action); ack({ ok: true }); } catch (e:any) { ack({ error: 'control_failed' }); }
    });
  });
}

