// src/services/signing.ts
import { pool } from '../infra/pg';
import { io } from '../server';
import { verifySignature } from '../crypto/sig';

export async function sign(workflowId:number, userId:number, signatureB64:string) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const w = await client.query('SELECT current_signer_idx, status FROM workflows WHERE id=$1 FOR UPDATE', [workflowId]);
    if (!w.rows[0] || w.rows[0].status !== 'active') { await client.query('ROLLBACK'); return { error: 'inactive' }; }
    const s = await client.query('SELECT user_id FROM signers WHERE workflow_id=$1 AND order_idx=$2', [workflowId, w.rows[0].current_signer_idx]);
    if (Number(s.rows[0].user_id) !== userId) { await client.query('ROLLBACK'); return { error: 'not_your_turn' }; }
    if (!verifySignature(signatureB64, userId)) { await client.query('ROLLBACK'); return { error: 'invalid_sig' }; }
    await client.query('UPDATE signers SET signature_b64=$1, signed_at=now() WHERE workflow_id=$2 AND order_idx=$3', [signatureB64, workflowId, w.rows[0].current_signer_idx]);
    const total = await client.query('SELECT count(*) AS n FROM signers WHERE workflow_id=$1', [workflowId]);
    const next = w.rows[0].current_signer_idx + 1;
    if (next >= Number(total.rows[0].n)) await client.query("UPDATE workflows SET status='completed', completed_at=now() WHERE id=$1", [workflowId]);
    else await client.query('UPDATE workflows SET current_signer_idx=$1 WHERE id=$2', [next, workflowId]);
    await client.query(`INSERT INTO workflow_events(workflow_id, type, actor_id, payload) VALUES ($1,'sign',$2,$3)`, [workflowId, userId, { idx: w.rows[0].current_signer_idx }]);
    await client.query('COMMIT');
    io.of('/signing').to(`wf:${workflowId}`).emit('wf:state', { workflowId: String(workflowId), currentSignerIdx: next, status: next >= Number(total.rows[0].n) ? 'completed' : 'active' });
    if (next >= Number(total.rows[0].n)) io.of('/signing').to(`wf:${workflowId}`).emit('wf:completed', { workflowId: String(workflowId) });
    return { ok: true };
  } catch (e) { await client.query('ROLLBACK'); throw e; } finally { client.release(); }
}

// src/socket/signing.namespace.ts
import { Namespace } from 'socket.io';
import { pool } from '../infra/pg';
import { sign } from '../services/signing';
export function registerSigningNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    socket.on('wf:subscribe', async ({ workflowId }, ack) => {
      const r = await pool.query('SELECT id, status, current_signer_idx FROM workflows WHERE id=$1', [workflowId]);
      const s = await pool.query('SELECT order_idx, user_id, signed_at, declined_at FROM signers WHERE workflow_id=$1 ORDER BY order_idx', [workflowId]);
      await socket.join(`wf:${workflowId}`);
      ack({ workflow: r.rows[0], signers: s.rows });
    });
    socket.on('sign', async ({ workflowId, signatureB64 }, ack) => { const r = await sign(workflowId, userId, signatureB64); ack(r); });
  });
}

