// src/services/mapReduce.ts
import { Job } from '../models/Job';
import { Shard } from '../models/Shard';
import { io } from '../server';
import { Queue, Worker } from 'bullmq';
import { redis } from '../infra/redis';
const shardQ = new Queue('mr:shard', { connection: redis });

export async function startJob(jobId:string, totalShards:number, type:string) {
  await Job.create({ _id: jobId, type, totalShards, completedShards: 0, status: 'running', createdAt: new Date() });
  for (let i = 0; i < totalShards; i++) { await Shard.create({ _id: `${jobId}:${i}`, jobId, idx: i, status: 'pending', progress: 0 }); await shardQ.add('run', { jobId, idx: i }); }
}

export function startMrWorker() {
  new Worker('mr:shard', async (job:any) => {
    const { jobId, idx } = job.data;
    const j = await Job.findById(jobId).lean();
    if (!j || j.status === 'cancelled') return;
    await Shard.updateOne({ _id: `${jobId}:${idx}` }, { $set: { status: 'running', startedAt: new Date() } });
    let progress = 0; let partial = 0;
    for (let step = 0; step < 10; step++) {
      const cur = await Job.findById(jobId).select('status').lean();
      if (cur?.status === 'cancelled') { await Shard.updateOne({ _id: `${jobId}:${idx}` }, { $set: { status: 'cancelled' } }); return; }
      progress += 10; partial += idx; // dummy work
      await Shard.updateOne({ _id: `${jobId}:${idx}` }, { $set: { progress, partialResult: partial } });
      io.of('/mr').to(`job:${jobId}`).emit('shard:progress', { jobId, idx, progress });
      await new Promise(r => setTimeout(r, 200));
    }
    await Shard.updateOne({ _id: `${jobId}:${idx}` }, { $set: { status: 'done', endedAt: new Date(), partialResult: partial } });
    const j2 = await Job.findByIdAndUpdate(jobId, { $inc: { completedShards: 1 } }, { new: true });
    if (j2 && j2.completedShards === j2.totalShards) {
      const shards = await Shard.find({ jobId, status: 'done' }).lean();
      const result = shards.reduce((s,sh) => s + (sh.partialResult as number ?? 0), 0);
      await Job.updateOne({ _id: jobId }, { $set: { status: 'completed', result, completedAt: new Date() } });
      io.of('/mr').to(`job:${jobId}`).emit('job:complete', { jobId, result });
    }
  }, { connection: redis });
}

// src/socket/mr.namespace.ts
import { Namespace } from 'socket.io';
import { Job } from '../models/Job';
import { Shard } from '../models/Shard';
export function registerMrNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    socket.on('job:subscribe', async ({ jobId }, ack) => {
      const j = await Job.findById(jobId).lean();
      if (!j) return ack({ error: 'no_job' });
      await socket.join(`job:${jobId}`);
      const shards = await Shard.find({ jobId }).lean();
      ack({ job: j, shards });
    });
    socket.on('job:cancel', async ({ jobId }) => { await Job.updateOne({ _id: jobId, status: 'running' }, { $set: { status: 'cancelled' } }); });
  });
}

