import { useEffect, useState } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSock(t:string){ if(sock) return sock; sock = io('/mr',{auth:{token:t},transports:['websocket']}); return sock; }
export function useMrJob(jobId:string, token:string) {
  const [job, setJob] = useState<any>(null);
  const [shards, setShards] = useState<Map<number,any>>(new Map());
  useEffect(() => {
    const s = getSock(token);
    const sub = () => s.emit('job:subscribe',{jobId},(r:any)=>{ setJob(r.job); setShards(new Map(r.shards.map((sh:any)=>[sh.idx, sh]))); });
    const onProg = (e:any) => { if (e.jobId !== jobId) return; setShards(p => { const n = new Map(p); const cur = n.get(e.idx) ?? { idx: e.idx }; n.set(e.idx, { ...cur, progress: e.progress }); return n; }); };
    const onDone = (e:any) => setJob((j:any) => ({ ...j, status: 'completed', result: e.result }));
    s.on('connect', sub); s.on('shard:progress', onProg); s.on('job:complete', onDone);
    if (s.connected) sub();
    return () => { s.off('connect', sub); s.off('shard:progress', onProg); s.off('job:complete', onDone); };
  }, [jobId, token]);
  return { job, shards: [...shards.values()] };
}

