// src/socket/sql.namespace.ts
import { Namespace } from 'socket.io';
import { pool, sandboxPool } from '../infra/pg';

export function registerSqlNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    socket.on('sess:join', async ({ sessionId }, ack) => {
      await socket.join(`sess:${sessionId}`);
      const { rows } = await pool.query('SELECT id, current_query, version FROM sql_sessions WHERE id=$1', [sessionId]);
      const runs = await pool.query('SELECT id, runner_id, query, explain_json, duration_ms, status, ran_at FROM sql_runs WHERE session_id=$1 ORDER BY id DESC LIMIT 20', [sessionId]);
      ack({ session: rows[0], runs: runs.rows });
    });
    socket.on('query:update', async ({ sessionId, query }) => {
      await pool.query('UPDATE sql_sessions SET current_query=$1, version=version+1, updated_at=now() WHERE id=$2', [query, sessionId]);
      socket.to(`sess:${sessionId}`).emit('query:peer', { query, by: userId });
    });
    socket.on('query:run', async ({ sessionId, query }, ack) => {
      if (/ (drop|alter|truncate|create) /i.test(query)) return ack({ error: 'ddl_forbidden' });
      const ins = await pool.query(`INSERT INTO sql_runs(session_id, runner_id, query, status) VALUES ($1,$2,$3,'running') RETURNING id`, [sessionId, userId, query]);
      const runId = ins.rows[0].id;
      try {
        const t0 = Date.now();
        const r = await sandboxPool.query(`EXPLAIN (FORMAT JSON, ANALYZE false) ${query}`);
        const ms = Date.now() - t0;
        await pool.query(`UPDATE sql_runs SET explain_json=$1, duration_ms=$2, status='done' WHERE id=$3`, [r.rows[0]['QUERY PLAN'], ms, runId]);
        nsp.to(`sess:${sessionId}`).emit('explain:result', { runId: String(runId), query, plan: r.rows[0]['QUERY PLAN'], durationMs: ms, by: userId });
        ack({ runId: String(runId), durationMs: ms });
      } catch (e:any) {
        await pool.query(`UPDATE sql_runs SET status='error' WHERE id=$1`, [runId]);
        ack({ error: e.message });
      }
    });
  });
}

