import { useEffect, useState, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSock(t:string){ if(sock) return sock; sock = io('/sql',{auth:{token:t},transports:['websocket']}); return sock; }
export function useSqlSession(sessionId:string, token:string) {
  const [session, setSession] = useState<any>(null);
  const [runs, setRuns] = useState<any[]>([]);
  const [explain, setExplain] = useState<any | null>(null);
  useEffect(() => {
    const s = getSock(token);
    const join = () => s.emit('sess:join',{sessionId},(r:any)=>{ setSession(r.session); setRuns(r.runs); });
    const onPeer = (e:any) => setSession((sn:any) => ({ ...sn, current_query: e.query }));
    const onResult = (e:any) => { setExplain(e); setRuns(p => [{ id: e.runId, query: e.query, explain_json: e.plan, duration_ms: e.durationMs }, ...p]); };
    s.on('connect', join); s.on('query:peer', onPeer); s.on('explain:result', onResult);
    if (s.connected) join();
    return () => { s.off('connect', join); s.off('query:peer', onPeer); s.off('explain:result', onResult); };
  }, [sessionId, token]);
  const updateQuery = useCallback((q:string) => getSock(token).emit('query:update',{sessionId,query:q}), [sessionId, token]);
  const run = useCallback((q:string) => new Promise((res,rej)=>getSock(token).emit('query:run',{sessionId,query:q},(r:any)=>r.error?rej(r):res(r))), [sessionId, token]);
  return { session, runs, explain, updateQuery, run };
}

