// src/socket/ai.namespace.ts
import { Namespace } from 'socket.io';
import { Convo } from '../models/Convo';
import Anthropic from '@anthropic-ai/sdk';
const anth = new Anthropic();

export function registerAiNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    const activeAborts = new Map<string, AbortController>();
    socket.on('convo:open', async ({ convoId }, ack) => {
      let c = await Convo.findById(convoId).lean();
      if (!c) { c = (await Convo.create({ _id: convoId, userId, messages: [] })).toObject(); }
      await socket.join(`convo:${convoId}`);
      ack({ messages: c.messages });
    });
    socket.on('msg:send', async ({ convoId, content }, ack) => {
      const c = await Convo.findById(convoId);
      if (!c) return ack({ error: 'no_convo' });
      c.messages.push({ role: 'user', content, createdAt: new Date() } as any);
      await c.save();
      const ac = new AbortController();
      activeAborts.set(convoId, ac);
      try {
        const stream = await anth.messages.stream({ model: 'claude-opus-4-7', max_tokens: 1024, messages: c.messages.map((m:any) => ({ role: m.role === 'assistant' ? 'assistant' : 'user', content: m.content })) }, { signal: ac.signal });
        let acc = '';
        for await (const event of stream) {
          if (event.type === 'content_block_delta' && event.delta.type === 'text_delta') {
            acc += event.delta.text;
            socket.emit('token', { convoId, text: event.delta.text });
          }
        }
        const final = await stream.finalMessage();
        c.messages.push({ role: 'assistant', content: acc, tokens: final.usage.output_tokens, createdAt: new Date(), finishReason: final.stop_reason } as any);
        await c.save();
        socket.emit('msg:done', { convoId, finishReason: final.stop_reason, tokens: final.usage.output_tokens });
        ack({ ok: true });
      } catch (e:any) {
        if (e.name === 'AbortError') { socket.emit('msg:done', { convoId, finishReason: 'cancelled' }); ack({ cancelled: true }); }
        else { socket.emit('msg:done', { convoId, finishReason: 'error', error: e.message }); ack({ error: e.message }); }
      } finally { activeAborts.delete(convoId); }
    });
    socket.on('cancel', ({ convoId }) => { activeAborts.get(convoId)?.abort(); });
    socket.on('disconnect', () => { for (const ac of activeAborts.values()) ac.abort(); activeAborts.clear(); });
  });
}

