// src/hooks/useAiChat.ts
import { useEffect, useState, useCallback, useRef } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSock(t:string){ if(sock) return sock; sock = io('/ai',{auth:{token:t},transports:['websocket']}); return sock; }
export function useAiChat(convoId:string, token:string) {
  const [messages, setMessages] = useState<any[]>([]);
  const [streaming, setStreaming] = useState(false);
  const accRef = useRef('');
  useEffect(() => {
    const s = getSock(token);
    const open = () => s.emit('convo:open',{convoId},(r:any)=>{ if(r.messages) setMessages(r.messages); });
    const onTok = (e:any) => { if (e.convoId !== convoId) return; accRef.current += e.text; setMessages(p => { const last = p[p.length-1]; if (last?.role === 'assistant' && last.streaming) return [...p.slice(0,-1), { ...last, content: accRef.current }]; return [...p, { role: 'assistant', content: accRef.current, streaming: true }]; }); };
    const onDone = (e:any) => { if (e.convoId !== convoId) return; accRef.current = ''; setStreaming(false); setMessages(p => p.map((m,i) => i === p.length-1 ? { ...m, streaming: false, finishReason: e.finishReason } : m)); };
    s.on('connect', open); s.on('token', onTok); s.on('msg:done', onDone);
    if (s.connected) open();
    return () => { s.off('connect', open); s.off('token', onTok); s.off('msg:done', onDone); };
  }, [convoId, token]);
  const send = useCallback((content:string) => { setMessages(p => [...p, { role: 'user', content }]); accRef.current = ''; setStreaming(true); getSock(token).emit('msg:send',{convoId,content},()=>{}); }, [convoId, token]);
  const cancel = useCallback(() => { getSock(token).emit('cancel',{convoId}); }, [convoId, token]);
  return { messages, streaming, send, cancel };
}

