// src/services/asyncGame.ts
import { pool } from '../infra/pg';
import { io } from '../server';
import { dispatchPush } from './pushDispatch';
import { validateMove, applyMove } from '../game/words';

export async function submitMove(matchId:number, userId:number, move:any) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const m = await client.query('SELECT p1, p2, current_turn, state, status FROM async_matches WHERE id=$1 FOR UPDATE', [matchId]);
    if (!m.rows[0] || m.rows[0].status !== 'active') { await client.query('ROLLBACK'); return { error: 'inactive' }; }
    const slot = userId === Number(m.rows[0].p1) ? 'p1' : (userId === Number(m.rows[0].p2) ? 'p2' : null);
    if (!slot || m.rows[0].current_turn !== slot) { await client.query('ROLLBACK'); return { error: 'not_your_turn' }; }
    const v = validateMove(m.rows[0].state, move);
    if (!v.ok) { await client.query('ROLLBACK'); return { error: 'invalid', reason: v.reason }; }
    const { newState, ended, winner } = applyMove(m.rows[0].state, move, slot);
    const next = slot === 'p1' ? 'p2' : 'p1';
    await client.query(`UPDATE async_matches SET state=$1, current_turn=$2, status=$3, last_move_at=now() WHERE id=$4`, [newState, next, ended ? 'ended' : 'active', matchId]);
    await client.query('INSERT INTO async_moves(match_id, player_id, move) VALUES ($1,$2,$3)', [matchId, userId, move]);
    await client.query('COMMIT');
    io.of('/async').to(`match:${matchId}`).emit('move:new', { matchId: String(matchId), move, by: userId, newState, ended, winner });
    const opponent = slot === 'p1' ? m.rows[0].p2 : m.rows[0].p1;
    await dispatchPush(String(opponent), { type: 'opponent_move', title: 'Your turn!', deepLink: `/match/${matchId}` });
    return { ok: true };
  } catch (e) { await client.query('ROLLBACK'); throw e; } finally { client.release(); }
}

