// src/services/ebAuction.ts
import { pool } from '../infra/pg';
import { io } from '../server';
import { redis } from '../infra/redis';

export async function bid(auctionId:number, userId:number, amountCents:number) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    await client.query('SELECT pg_advisory_xact_lock($1)', [auctionId]);
    const a = await client.query('SELECT current_bid_cents, current_bidder_id, ends_at, reserve_cents, status FROM eb_auctions WHERE id=$1 FOR UPDATE', [auctionId]);
    if (!a.rows[0] || a.rows[0].status !== 'live') { await client.query('ROLLBACK'); return { error: 'inactive' }; }
    if (new Date(a.rows[0].ends_at).getTime() <= Date.now()) { await client.query('ROLLBACK'); return { error: 'ended' }; }
    if (amountCents < Number(a.rows[0].current_bid_cents) + 100) { await client.query('ROLLBACK'); return { error: 'too_low' }; }
    const previousBidder = a.rows[0].current_bidder_id;
    const newEnd = (new Date(a.rows[0].ends_at).getTime() - Date.now() < 30_000) ? new Date(Date.now() + 5*60*1000) : new Date(a.rows[0].ends_at);
    const reserveMet = amountCents >= Number(a.rows[0].reserve_cents ?? 0);
    await client.query('UPDATE eb_auctions SET current_bid_cents=$1, current_bidder_id=$2, ends_at=$3, reserve_met=$4 WHERE id=$5', [amountCents, userId, newEnd, reserveMet, auctionId]);
    await client.query('INSERT INTO eb_bids(auction_id, bidder_id, amount_cents) VALUES ($1,$2,$3)', [auctionId, userId, amountCents]);
    await client.query('COMMIT');
    io.of('/ebay').to(`auction:${auctionId}`).emit('auction:state', { auctionId: String(auctionId), currentBidCents: amountCents, currentBidderId: String(userId), endsAt: newEnd.getTime(), reserveMet });
    if (newEnd.getTime() !== new Date(a.rows[0].ends_at).getTime()) io.of('/ebay').to(`auction:${auctionId}`).emit('extended', { auctionId: String(auctionId), endsAt: newEnd.getTime() });
    if (previousBidder && Number(previousBidder) !== userId) io.of('/ebay').to(`user:${previousBidder}`).emit('outbid', { auctionId: String(auctionId), currentBidCents: amountCents });
    return { ok: true };
  } catch (e) { await client.query('ROLLBACK'); throw e; } finally { client.release(); }
}

// src/socket/ebay.namespace.ts
import { Namespace } from 'socket.io';
import { pool } from '../infra/pg';
import { redis } from '../infra/redis';
import { bid } from '../services/ebAuction';
export function registerEbayNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    socket.join(`user:${userId}`);
    socket.on('auction:watch', async ({ auctionId }, ack) => {
      await socket.join(`auction:${auctionId}`);
      await redis.sadd(`watchers:${auctionId}`, socket.id);
      const watcherCount = await redis.scard(`watchers:${auctionId}`);
      nsp.to(`auction:${auctionId}`).emit('watchers', { auctionId, count: watcherCount });
      const a = await pool.query('SELECT id, current_bid_cents, current_bidder_id, ends_at, reserve_met FROM eb_auctions WHERE id=$1', [auctionId]);
      ack({ auction: a.rows[0], watcherCount });
    });
    socket.on('bid', async ({ auctionId, amountCents }, ack) => { const r = await bid(auctionId, userId, amountCents); ack(r); });
    socket.on('disconnect', async () => { /* per-room cleanup omitted */ });
  });
}

