// src/socket/crm.namespace.ts
import { Namespace } from 'socket.io';
import { redis } from '../infra/redis';
import { pool } from '../infra/pg';
import { io } from '../server';
const active = new Set<string>();

export function registerCrmNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    const repId = socket.data.user.id;
    const repRole = socket.data.user.role;
    socket.on('deal:open', async ({ dealId }) => {
      await socket.join(`deal:${dealId}`);
      await redis.hset(`deal:viewers:${dealId}`, repId, JSON.stringify({ repRole, ts: Date.now(), intent: 'view' }));
      await redis.expire(`deal:viewers:${dealId}`, 60);
      active.add(dealId);
    });
    socket.on('deal:edit:start', async ({ dealId }) => { await redis.hset(`deal:viewers:${dealId}`, repId, JSON.stringify({ repRole, ts: Date.now(), intent: 'edit' })); });
    socket.on('deal:edit:end', async ({ dealId }) => { await redis.hset(`deal:viewers:${dealId}`, repId, JSON.stringify({ repRole, ts: Date.now(), intent: 'view' })); });
    socket.on('deal:close', async ({ dealId }) => { await redis.hdel(`deal:viewers:${dealId}`, repId); await socket.leave(`deal:${dealId}`); });
    socket.on('disconnect', async () => { /* sweep */ });
  });
  setInterval(async () => {
    for (const dealId of active) {
      const map = await redis.hgetall(`deal:viewers:${dealId}`);
      if (Object.keys(map).length === 0) { active.delete(dealId); continue; }
      const sockets = await io.of('/crm').in(`deal:${dealId}`).fetchSockets();
      for (const s of sockets) {
        const viewer = (s.data as any).user;
        const visible = await pool.query('SELECT visible FROM crm_visibility WHERE viewer_id=$1 AND target_role=ANY($2::text[])', [viewer.id, Object.values(map).map((v:any)=>JSON.parse(v).repRole)]);
        const filtered: any[] = [];
        for (const [rid, val] of Object.entries(map)) {
          const v = JSON.parse(val as string);
          if (viewer.role === 'manager' || visible.rows.some((r:any) => r.visible)) filtered.push({ repId: rid, intent: v.intent });
        }
        s.emit('viewers', { dealId, viewers: filtered });
      }
    }
  }, 5000);
}

