    const userId = socket.data.user.id;
    socket.on('img:open', async ({ imageId }, ack) => {
      const img = await pool.query('SELECT id, current_version FROM images WHERE id=$1', [imageId]);
      if (!img.rows[0]) return ack({ error: 'no_img' });
      await socket.join(`img:${imageId}`);
      const pins = await Pin.find({ imageId, imageVersion: img.rows[0].current_version, resolved: false }).lean();
      ack({ image: img.rows[0], pins });
    });
    socket.on('pin:add', async ({ imageId, x, y, body }, ack) => {
      const img = await pool.query('SELECT current_version FROM images WHERE id=$1', [imageId]);
      const p = await Pin.create({ _id: uuid(), imageId, imageVersion: img.rows[0].current_version, x, y, body, authorId: userId });
      io.of('/images').to(`img:${imageId}`).emit('pin:added', p.toObject());
      ack({ pin: p.toObject() });
    });
