// src/socket/cctv.namespace.ts
import { Namespace } from 'socket.io';
import { sub } from '../infra/redis';
export function registerCctvNamespace(nsp: Namespace) {
  nsp.use(authMw);
  sub.psubscribe('cctv:cam:*');
  const subs = new Map<string, { cameraId:string; classes:Set<string>|null }>();
  sub.on('pmessage', async (_p, ch, payload) => {
    const cid = ch.split(':')[2];
    const d = JSON.parse(payload);
    const sockets = await io.of('/cctv').in(`cam:${cid}`).fetchSockets();
    for (const s of sockets) {
      const cfg = subs.get(s.id); if (!cfg) continue;
      const filtered = cfg.classes ? d.objects.filter((o:any) => cfg.classes!.has(o.class)) : d.objects;
      if (filtered.length) s.emit('detection', { cameraId: cid, frameTs: d.frameTs, objects: filtered });
    }
  });
  nsp.on('connection', (socket) => {
    socket.on('cam:subscribe', async ({ cameraId, classes }, ack) => {
      await socket.join(`cam:${cameraId}`);
      subs.set(socket.id, { cameraId, classes: classes && classes.length ? new Set<string>(classes) : null });
      ack({ ok: true });
    });
    socket.on('disconnect', () => subs.delete(socket.id));
  });
}

