// src/services/hybridCall.ts
import { HybridRoom } from '../models/HybridRoom';
import { sfuClient } from '../infra/sfu';
import { io } from '../server';

const P2P_LIMIT = 4;

export async function joinRoom(roomId:string, userId:string) {
  const r = await HybridRoom.findOneAndUpdate({ _id: roomId, 'participants.userId': { $ne: userId } }, { $push: { participants: { userId, joinedAt: new Date() } } }, { upsert: true, new: true });
  if (r.participants.length > P2P_LIMIT && r.mode === 'p2p') await switchToSfu(roomId);
  if (r.participants.length <= P2P_LIMIT && r.mode === 'sfu') { /* could downgrade, omitted */ }
  return r;
}

export async function switchToSfu(roomId:string) {
  const room = await HybridRoom.findById(roomId);
  if (!room || room.mode === 'sfu') return;
  try {
    const transports: Record<string, string> = {};
    for (const p of room.participants) { const t = await sfuClient.createTransport(roomId, p.userId); transports[p.userId] = t.id; }
    await HybridRoom.updateOne({ _id: roomId }, { $set: { mode: 'sfu', sfuTransportIds: transports } });
    io.of('/hybrid').to(`room:${roomId}`).emit('mode:switch', { mode: 'sfu', transports });
  } catch (e) {
    // SFU unavailable — keep p2p but cap. Mark room as 'capped'.
    io.of('/hybrid').to(`room:${roomId}`).emit('mode:switch', { mode: 'p2p', error: 'sfu_unavailable_capped' });
  }
}

