// src/services/timesheet.ts
import { pool } from '../infra/pg';
import { io } from '../server';

export async function bulkFill(sheetId:number, userId:number, cells:{projectId:number;day:string;hours:number}[]) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    await client.query('SELECT pg_advisory_xact_lock($1)', [sheetId]);
    for (const c of cells) {
      await client.query('INSERT INTO time_cells(sheet_id, project_id, day, hours, edited_by) VALUES ($1,$2,$3,$4,$5) ON CONFLICT (sheet_id, project_id, day) DO UPDATE SET hours=EXCLUDED.hours, edited_by=EXCLUDED.edited_by, edited_at=now()', [sheetId, c.projectId, c.day, c.hours, userId]);
    }
    // weekly total validation
    const tot = await client.query('SELECT day, sum(hours) AS h FROM time_cells WHERE sheet_id=$1 GROUP BY day', [sheetId]);
    const errors = tot.rows.filter((r:any) => Number(r.h) > 24).map((r:any) => ({ day: r.day, error: 'over_24h' }));
    const weekTotal = tot.rows.reduce((s,r) => s + Number(r.h), 0);
    if (weekTotal > 60) errors.push({ error: 'week_over_60h' });
    await client.query('COMMIT');
    io.of('/timesheet').to(`sheet:${sheetId}`).emit('cell:updated', { cells, by: userId });
    if (errors.length) io.of('/timesheet').to(`sheet:${sheetId}`).emit('validation:errors', { errors });
    return { ok: true, errors };
  } catch (e) { await client.query('ROLLBACK'); throw e; } finally { client.release(); }
}

