// src/workers/exportWorker.ts
import { pool } from '../infra/pg';
import { Queue, Worker } from 'bullmq';
import { redis } from '../infra/redis';
import { S3 } from '@aws-sdk/client-s3';
import { io } from '../server';
import { sendEmail } from '../infra/email';
const expQ = new Queue('exports', { connection: redis });
const s3 = new S3({});

export async function startExport(exportId:string) {
  await expQ.add('run', { exportId });
}

export function startExportWorker() {
  new Worker('exports', async (job:any) => {
    const { exportId } = job.data;
    const e = (await pool.query('SELECT id, user_id, s3_key, s3_upload_id, processed_rows, total_rows FROM exports WHERE id=$1', [exportId])).rows[0];
    if (!e) return;
    let key = e.s3_key || `exports/${exportId}.csv`;
    let uploadId = e.s3_upload_id;
    if (!uploadId) { const init = await s3.createMultipartUpload({ Bucket: 'exports', Key: key }); uploadId = init.UploadId; await pool.query('UPDATE exports SET s3_key=$1, s3_upload_id=$2 WHERE id=$3', [key, uploadId, exportId]); }
    const client = await pool.connect();
    try {
      await pool.query("UPDATE exports SET status='running' WHERE id=$1", [exportId]);
      const cursor = client.query('SELECT * FROM big_table OFFSET $1', [Number(e.processed_rows)]) as any;
      let processed = Number(e.processed_rows);
      let partNum = (await pool.query('SELECT parts FROM exports WHERE id=$1', [exportId])).rows[0].parts.length + 1;
      let buf: string[] = [];
      const flushPart = async () => {
        if (!buf.length) return;
        const body = buf.join('\n');
        const part = await s3.uploadPart({ Bucket: 'exports', Key: key, UploadId: uploadId, PartNumber: partNum, Body: body });
        await pool.query("UPDATE exports SET parts = parts || jsonb_build_array(jsonb_build_object('PartNumber', $1::int, 'ETag', $2::text)), processed_rows=$3 WHERE id=$4", [partNum, part.ETag, processed, exportId]);
        io.of('/exports').to(`export:${exportId}`).emit('progress', { processed, total: Number(e.total_rows) });
        partNum++; buf = [];
      };
      for await (const row of cursor) {
        const cancelled = await redis.get(`exp:cancel:${exportId}`);
        if (cancelled) { await s3.abortMultipartUpload({ Bucket: 'exports', Key: key, UploadId: uploadId }); await pool.query("UPDATE exports SET status='cancelled' WHERE id=$1", [exportId]); io.of('/exports').to(`export:${exportId}`).emit('done', { status: 'cancelled' }); return; }
        buf.push(Object.values(row).join(','));
        processed++;
        if (buf.join('\n').length > 5_000_000) await flushPart();
      }
      if (buf.length) await flushPart();
      const parts = (await pool.query('SELECT parts FROM exports WHERE id=$1', [exportId])).rows[0].parts;
      await s3.completeMultipartUpload({ Bucket: 'exports', Key: key, UploadId: uploadId, MultipartUpload: { Parts: parts } });
      await pool.query("UPDATE exports SET status='done', completed_at=now() WHERE id=$1", [exportId]);
      io.of('/exports').to(`export:${exportId}`).emit('done', { status: 'done', s3Key: key });
      try { await sendEmail(e.user_id, 'Export ready', { url: `https://exports.example/${key}` }); } catch {}
    } finally { client.release(); }
  }, { connection: redis });
}

