// src/socket/mindmap.namespace.ts
import { Namespace } from 'socket.io';
import { MapNode } from '../models/MapNode';
import mongoose from 'mongoose';
import { io } from '../server';
import { v4 as uuid } from 'uuid';

export function registerMindmapNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    socket.on('map:open', async ({ mapId }, ack) => {
      await socket.join(`map:${mapId}`);
      const nodes = await MapNode.find({ mapId }).lean();
      ack({ nodes });
    });
    socket.on('node:add', async ({ mapId, parentId, text, order }, ack) => {
      const n = await MapNode.create({ _id: uuid(), mapId, parentId, text, order: order ?? 0 });
      io.of('/mindmap').to(`map:${mapId}`).emit('node:added', n.toObject());
      ack({ node: n.toObject() });
    });
    socket.on('node:reparent', async ({ nodeId, newParentId, newOrder }, ack) => {
      // cycle detect: walk newParentId up; if reaches nodeId, cycle
      const session = await mongoose.startSession();
      try {
        let result:any;
        await session.withTransaction(async () => {
          let cur: any = await MapNode.findById(newParentId, null, { session });
          while (cur) { if (String(cur._id) === nodeId) { result = { error: 'cycle' }; return; } cur = await MapNode.findById(cur.parentId, null, { session }); }
          const n = await MapNode.findByIdAndUpdate(nodeId, { $set: { parentId: newParentId, order: newOrder ?? 0 }, $inc: { version: 1 } }, { new: true, session });
          result = { ok: true, node: n?.toObject() };
        });
        if (result.ok) io.of('/mindmap').to(`map:${result.node.mapId}`).emit('node:reparented', { nodeId, newParentId, newOrder });
        ack(result);
      } finally { await session.endSession(); }
    });
    socket.on('node:reorder', async ({ mapId, ordered }, ack) => {
      const ops = ordered.map((id:string, i:number) => ({ updateOne: { filter: { _id: id }, update: { $set: { order: i } } } }));
      await MapNode.bulkWrite(ops);
      io.of('/mindmap').to(`map:${mapId}`).emit('node:reordered', { ordered });
      ack({ ok: true });
    });
    socket.on('node:delete', async ({ nodeId, mapId }, ack) => {
      // delete subtree
      const all = await MapNode.find({ mapId }).lean();
      const toDelete = new Set([nodeId]);
      let changed = true;
      while (changed) { changed = false; for (const n of all) if (toDelete.has(n.parentId) && !toDelete.has(String(n._id))) { toDelete.add(String(n._id)); changed = true; } }
      await MapNode.deleteMany({ _id: { $in: [...toDelete] } });
      io.of('/mindmap').to(`map:${mapId}`).emit('node:deleted', { nodeIds: [...toDelete] });
      ack({ ok: true, count: toDelete.size });
    });
  });
}

