import { useEffect, useState, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSock(t:string){ if(sock) return sock; sock = io('/mindmap',{auth:{token:t},transports:['websocket']}); return sock; }
export function useMindMap(mapId:string, token:string) {
  const [nodes, setNodes] = useState<any[]>([]);
  useEffect(() => {
    const s = getSock(token);
    const open = () => s.emit('map:open',{mapId},(r:any)=>{ if(r.nodes) setNodes(r.nodes); });
    const onAdd = (n:any) => setNodes(p => [...p, n]);
    const onRep = ({nodeId,newParentId,newOrder}:any) => setNodes(p => p.map(n => n._id === nodeId ? { ...n, parentId: newParentId, order: newOrder } : n));
    const onReord = ({ordered}:any) => setNodes(p => { const idx = new Map(ordered.map((id:string,i:number)=>[id,i])); return p.map(n => idx.has(n._id) ? { ...n, order: idx.get(n._id) } : n); });
    const onDel = ({nodeIds}:any) => setNodes(p => p.filter(n => !nodeIds.includes(n._id)));
    s.on('connect', open); s.on('node:added', onAdd); s.on('node:reparented', onRep); s.on('node:reordered', onReord); s.on('node:deleted', onDel);
    if (s.connected) open();
    return () => { s.off('connect', open); s.off('node:added', onAdd); s.off('node:reparented', onRep); s.off('node:reordered', onReord); s.off('node:deleted', onDel); };
  }, [mapId, token]);
  const add = useCallback((parentId:string, text:string, order:number) => new Promise((res,rej)=>getSock(token).emit('node:add',{mapId,parentId,text,order},(r:any)=>r.error?rej(r):res(r))), [mapId, token]);
  const reparent = useCallback((nodeId:string, newParentId:string, newOrder:number) => new Promise((res,rej)=>getSock(token).emit('node:reparent',{nodeId,newParentId,newOrder},(r:any)=>r.error?rej(r):res(r))), [token]);
  return { nodes, add, reparent };
}

