// src/services/support.ts
import { pool } from '../infra/pg';
import { translate } from '../infra/translation';
import { io } from '../server';
import crypto from 'crypto';

async function getOrTranslate(text:string, target:string) {
  const hash = crypto.createHash('sha256').update(text).digest('hex');
  const cached = await pool.query('SELECT text FROM translation_cache WHERE hash=$1 AND target_lang=$2', [hash, target]);
  if (cached.rows[0]) return cached.rows[0].text;
  try {
    const t = await translate(text, target);
    await pool.query('INSERT INTO translation_cache(hash, target_lang, text) VALUES ($1,$2,$3) ON CONFLICT DO NOTHING', [hash, target, t]);
    return t;
  } catch { return text; /* fallback to original */ }
}

export async function sendMsg(chatId:number, senderId:number, body:string) {
  const c = await pool.query('SELECT customer_lang, agent_lang FROM chats WHERE id=$1', [chatId]);
  if (!c.rows[0]) return { error: 'no_chat' };
  const detected = 'auto'; // detect
  const ins = await pool.query('INSERT INTO chat_messages(chat_id, sender_id, body, lang) VALUES ($1,$2,$3,$4) RETURNING id, ts', [chatId, senderId, body, detected]);
  const customerTr = await getOrTranslate(body, c.rows[0].customer_lang);
  const agentTr = await getOrTranslate(body, c.rows[0].agent_lang);
  io.of('/support').to(`chat:${chatId}`).emit('msg:new', { id: String(ins.rows[0].id), chatId: String(chatId), senderId: String(senderId), body, customerTr, agentTr, ts: ins.rows[0].ts });
  return { ok: true };
}

// src/socket/support.namespace.ts
import { Namespace } from 'socket.io';
import { pool } from '../infra/pg';
import { sendMsg } from '../services/support';
export function registerSupportNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    socket.on('chat:open', async ({ chatId }, ack) => {
      await socket.join(`chat:${chatId}`);
      const m = await pool.query('SELECT id, sender_id, body, lang, ts FROM chat_messages WHERE chat_id=$1 ORDER BY id', [chatId]);
      const cans = await pool.query('SELECT hotkey, template FROM canned_responses WHERE agent_id=$1', [userId]);
      ack({ messages: m.rows, cans: cans.rows });
    });
    socket.on('msg:send', async ({ chatId, body }, ack) => { const r = await sendMsg(chatId, userId, body); ack(r); });
    socket.on('canned:expand', async ({ canId, vars }, ack) => {
      const c = await pool.query('SELECT template FROM canned_responses WHERE id=$1 AND agent_id=$2', [canId, userId]);
      if (!c.rows[0]) return ack({ error: 'no_canned' });
      const expanded = c.rows[0].template.replace(/\{(\w+)\}/g, (_:string,k:string) => vars[k] ?? '');
      ack({ text: expanded });
    });
  });
}

