// src/services/opsHub.ts
import { pool } from '../infra/pg';
import { redis, sub } from '../infra/redis';
import { io } from '../server';

type Filter = { merchantIds?:number[]; severities?:string[]; types?:string[] };
const subs = new Map<string, { filter: Filter; predicate: (e:any)=>boolean }>();

function compile(f: Filter) {
  const mids = f.merchantIds ? new Set(f.merchantIds.map(Number)) : null;
  const sev = f.severities ? new Set(f.severities) : null;
  const types = f.types ? new Set(f.types) : null;
  return (e:any) => (!mids || mids.has(Number(e.merchantId))) && (!sev || sev.has(e.severity)) && (!types || types.has(e.type));
}

export async function ingestEvent(source:string, type:string, merchantId:number, orderId:number|null, severity:string, payload:any) {
  const r = await pool.query('INSERT INTO ops_events(source, type, merchant_id, order_id, severity, payload) VALUES ($1,$2,$3,$4,$5,$6) RETURNING id, ts', [source, type, merchantId, orderId, severity, payload]);
  const evt = { id: String(r.rows[0].id), source, type, merchantId, orderId, severity, payload, ts: r.rows[0].ts };
  await redis.publish('ops:events', JSON.stringify(evt));
  return evt;
}

export function startOpsFanout(nsp:any) {
  sub.subscribe('ops:events');
  sub.on('message', async (ch, payload) => {
    if (ch !== 'ops:events') return;
    const evt = JSON.parse(payload);
    for (const [sid, cfg] of subs) {
      const target = nsp.sockets.get(sid);
      if (target && cfg.predicate(evt)) target.emit('event', evt);
    }
  });
}

// src/socket/ops.namespace.ts
import { Namespace } from 'socket.io';
import { pool } from '../infra/pg';
import { startOpsFanout } from '../services/opsHub';
export function registerOpsNamespace(nsp: Namespace) {
  nsp.use(authMw);
  startOpsFanout(nsp);
  nsp.on('connection', (socket) => {
    socket.on('feed:subscribe', async ({ filter, sinceTs }, ack) => {
      const pred = compile(filter ?? {});
      subs.set(socket.id, { filter, predicate: pred });
      const since = sinceTs ? new Date(sinceTs) : new Date(Date.now() - 60*60_000);
      const { rows } = await pool.query('SELECT id, source, type, merchant_id, order_id, severity, payload, ts FROM ops_events WHERE ts > $1 ORDER BY ts LIMIT 1000', [since]);
      const filtered = rows.filter((r:any) => pred({ ...r, merchantId: r.merchant_id, orderId: r.order_id }));
      ack({ history: filtered });
    });
    socket.on('feed:filter', ({ filter }, ack) => { const pred = compile(filter); subs.set(socket.id, { filter, predicate: pred }); ack({ ok: true }); });
    socket.on('disconnect', () => subs.delete(socket.id));
  });
}
function compile(f:any){ /* defined above; copy for module scope */ return ()=>true; }

