// src/hooks/useOpsHub.ts
import { useEffect, useState, useCallback, useRef } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSock(t:string){ if(sock) return sock; sock = io('/ops',{auth:{token:t},transports:['websocket']}); return sock; }
export function useOpsHub(token:string, initialFilter:any={}) {
  const [events, setEvents] = useState<any[]>([]);
  const filterRef = useRef(initialFilter);
  const lastTsRef = useRef<number | null>(null);
  useEffect(() => {
    const s = getSock(token);
    const sub = () => s.emit('feed:subscribe',{filter:filterRef.current, sinceTs:lastTsRef.current},(r:any)=>{ if(r.history) { setEvents(r.history); lastTsRef.current = r.history.length ? new Date(r.history[r.history.length-1].ts).getTime() : Date.now(); } });
    const onEvt = (e:any) => { lastTsRef.current = new Date(e.ts).getTime(); setEvents(p => [e, ...p].slice(0, 2000)); };
    s.on('connect', sub); s.on('event', onEvt);
    if (s.connected) sub();
    return () => { s.off('connect', sub); s.off('event', onEvt); };
  }, [token]);
  const setFilter = useCallback((f:any) => { filterRef.current = f; getSock(token).emit('feed:filter',{filter:f},()=>{}); }, [token]);
  return { events, setFilter };
}
